// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// Interface for legacy ZK Verifier (old age-check circuit, 3 public inputs)
interface IVerifier {
    function verifyProof(
        uint[2] memory a,
        uint[2][2] memory b,
        uint[2] memory c,
        uint[3] memory input
    ) external view returns (bool);
}

// Interface for Groth16Verifier generated from VoteWithICAgeCheck circuit (Verifier.sol)
// Public signals order: [ageThreshold, nullifierHash, electionId, voterCommitment, currentYear, currentMonth, currentDay]
interface IVoteVerifier {
    function verifyProof(
        uint[2] calldata _pA,
        uint[2][2] calldata _pB,
        uint[2] calldata _pC,
        uint[7] calldata _pubSignals
    ) external view returns (bool);
}

contract Contract {
    // ===== PHASE 1: Paillier & Trustee Management =====
    struct Trustee {
        address walletAddress;
        bytes32 shareCommitment;  // Hash of the secret share
        bool hasSubmittedCommitment;
        uint256 registeredAt;
    }

    // Paillier Public Key Storage
    string public paillierPublicKeyN;  // Stored as string to handle large numbers
    bool public isPaillierKeySet;
    
    // Trustee Management
    address[] public trusteeAddresses;
    mapping(address => Trustee) public trustees;
    uint256 public threshold;  // Minimum trustees needed for decryption
    uint256 public numTrustees;  // Total number of trustees
    
    event PaillierPublicKeySet(string publicKeyN, uint256 timestamp);
    event TrusteeRegistered(address indexed trusteeAddress, uint256 timestamp);
    event ShareCommitmentSubmitted(address indexed trusteeAddress, bytes32 commitment, uint256 timestamp);
    
    // ===== EXISTING STRUCTS =====
    struct Voter {
        address wallet;
        string name;
        bytes32 icHash;
        string email;
        string status;
        bytes32 verificationCode;
        uint256 registeredAt;
        uint256 verifiedAt;
        bool isRegistered;
    }

    struct Candidate {
        address wallet;
        string name;
        bytes32 icHash;
        string email;
        string party;
        string manifesto;
        string status;
        bytes32 verificationCode;
        uint256 registeredAt;
        uint256 verifiedAt;
        bool isRegistered;
    }

    struct Organizer {
        address wallet;
        string organizationName;
        string email;
        string description;
        string status;
        uint256 registeredAt;
        bool isRegistered;
    }

    struct Election {
        uint256 id;
        string title;
        string description;
        address organizer;
        uint256 nominationStartTime;
        uint256 nominationEndTime;
        uint256 startTime;
        uint256 endTime;
        bool isActive;
        uint256 createdAt;
        uint256 totalVotes;
        string encryptedTally;  // Homomorphically aggregated encrypted total
        bool tallyStored;
        // ===== PHASE 4 =====
        string decryptedResult;  // JSON-encoded decrypted tally per candidate
        bool resultsPublished;
    }
    
    // ===== PHASE 2: Encrypted Voting =====
    struct EncryptedVote {
        uint256 electionId;
        address voter;
        string ipfsCID;  // IPFS CID where encrypted vote is stored
        uint256 timestamp;
        bool exists;
    }
    
    event EncryptedVoteCast(
        uint256 indexed electionId,
        address indexed voter,
        uint256 timestamp
    );
    
    event EncryptedTallyStored(
        uint256 indexed electionId,
        string encryptedTally,
        uint256 totalVotesCounted,
        uint256 timestamp
    );
    
    // ===== PHASE 4 Events =====
    event DecryptionShareSubmitted(
        uint256 indexed electionId,
        address indexed trustee,
        bytes32 shareHash,
        uint256 timestamp
    );
    
    event ResultsPublished(
        uint256 indexed electionId,
        string decryptedResult,
        uint256 timestamp
    );
    
    // ===== STATE VARIABLES =====
    address public admin;
    IVerifier public verifier;  // ZK Verifier contract
    address[] private voterAddresses;
    address[] private candidateAddresses;
    address[] private organizerList;
    
    uint256 private electionCounter;
    uint256[] private electionIds;
    mapping(uint256 => Election) public elections;

    mapping(bytes32 => bool) private usedICs;
    mapping(string => bool) private usedEmails;

    mapping(address => Voter) public voters;
    mapping(address => Candidate) public candidates;
    mapping(address => Organizer) public organizers;
    
    // Election-scoped candidacy (Phase 3 & 4)
    mapping(uint256 => address[]) private electionCandidateApplicants;
    mapping(uint256 => mapping(address => uint8)) public candidateApplicationStatus;
    mapping(uint256 => mapping(address => bool)) public hasVoted;
    // candidateVotes removed - using encrypted voting instead
    
    // Phase 2: Encrypted votes storage
    mapping(uint256 => mapping(address => EncryptedVote)) private encryptedVotes;
    mapping(uint256 => address[]) private encryptedVoters;  // Track voters per election

    // ===== ZKP VOTING =====
    IVoteVerifier public voteVerifier;
    // Poseidon commitment: H(voterAddress, voterSecret) — stored during voter verification
    mapping(bytes32 => bool) public voterCommitments;
    // Nullifier: H(voterSecret, electionId) — prevents double voting anonymously
    mapping(uint256 => mapping(bytes32 => bool)) public nullifierUsed;
    // Anonymous vote storage: electionId => nullifier => ipfsCID
    mapping(uint256 => mapping(bytes32 => string)) private zkpVotes;
    // Nullifiers list per election (for tally)
    mapping(uint256 => bytes32[]) private zkpVoteNullifiers;

    event VoterCommitmentStored(bytes32 indexed commitment, uint256 timestamp);
    event ZKPVoteCast(uint256 indexed electionId, bytes32 indexed nullifierHash, uint256 timestamp);

    // ===== PHASE 4: Threshold Decryption State =====
    mapping(uint256 => mapping(address => bool)) public hasSubmittedDecryptionShare;
    mapping(uint256 => uint256) public decryptionShareCount;
    
    constructor(address[] memory _trusteeAddresses, uint256 _threshold) {
        require(_trusteeAddresses.length >= 2, "!trustees");
        require(_threshold >= 2, "!threshold");
        require(_threshold <= _trusteeAddresses.length, "!t<=n");
        
        admin = msg.sender;
        trusteeAddresses = _trusteeAddresses;
        threshold = _threshold;
        numTrustees = _trusteeAddresses.length;
        
        // Register trustees
        for (uint256 i = 0; i < _trusteeAddresses.length; i++) {
            address trusteeAddr = _trusteeAddresses[i];
            require(trusteeAddr != address(0), "!addr");
            
            trustees[trusteeAddr] = Trustee({
                walletAddress: trusteeAddr,
                shareCommitment: bytes32(0),
                hasSubmittedCommitment: false,
                registeredAt: block.timestamp
            });
            
            emit TrusteeRegistered(trusteeAddr, block.timestamp);
        }
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "!admin");
        _;
    }
    
    modifier onlyTrustee() {
        require(trustees[msg.sender].walletAddress != address(0), "!trustee");
        _;
    }
    
    // Set ZK Verifier contract address
    function setVerifier(address _verifier) public onlyAdmin {
        require(_verifier != address(0), "!addr");
        verifier = IVerifier(_verifier);
    }

    // Set ZKP Vote Verifier contract (VoteWithICAgeCheck verifier)
    function setVoteVerifier(address _voteVerifier) public onlyAdmin {
        require(_voteVerifier != address(0), "!addr");
        voteVerifier = IVoteVerifier(_voteVerifier);
    }

    /**
     * @dev Store a voter's Poseidon commitment H(voterAddress, voterSecret).
     *      Called by admin after voter is VERIFIED, so the commitment is on-chain
     *      and can be checked during ZKP voting without revealing who the voter is.
     * @param _commitment Poseidon hash of (voterAddress, voterSecret)
     */
    function storeVoterCommitment(bytes32 _commitment) public onlyAdmin {
        require(_commitment != bytes32(0), "!commit");
        require(!voterCommitments[_commitment], "exists");
        voterCommitments[_commitment] = true;
        emit VoterCommitmentStored(_commitment, block.timestamp);
    }

    // ===== PHASE 1: Paillier & Trustee Functions =====
    
    /**
     * @dev Set the Paillier public key (can only be set once by admin)
     * @param _publicKeyN The public key modulus N as a string
     */
    function setPaillierPublicKey(string memory _publicKeyN) public onlyAdmin {
        require(!isPaillierKeySet, "!keySet");
        require(bytes(_publicKeyN).length > 0, "!key");
        
        paillierPublicKeyN = _publicKeyN;
        isPaillierKeySet = true;
        
        emit PaillierPublicKeySet(_publicKeyN, block.timestamp);
    }
    
    /**
     * @dev Submit a commitment (hash) of the trustee's secret share
     * @param _commitment Hash of the secret share (keccak256 of share data)
     */
    function submitShareCommitment(bytes32 _commitment) public onlyTrustee {
        require(!trustees[msg.sender].hasSubmittedCommitment, "!committed");
        require(_commitment != bytes32(0), "!commit");
        
        trustees[msg.sender].shareCommitment = _commitment;
        trustees[msg.sender].hasSubmittedCommitment = true;
        
        emit ShareCommitmentSubmitted(msg.sender, _commitment, block.timestamp);
    }
    
    /**
     * @dev Get Paillier public key
     */
    function getPaillierPublicKey() public view returns (string memory) {
        require(isPaillierKeySet, "!key");
        return paillierPublicKeyN;
    }
    
    /**
     * @dev Get list of all trustee addresses
     */
    function getTrusteeAddresses() public view returns (address[] memory) {
        return trusteeAddresses;
    }
    
    /**
     * @dev Check if all trustees have submitted their commitments
     */
    function allTrusteesCommitted() public view returns (bool) {
        for (uint256 i = 0; i < trusteeAddresses.length; i++) {
            if (!trustees[trusteeAddresses[i]].hasSubmittedCommitment) {
                return false;
            }
        }
        return true;
    }
    
    /**
     * @dev Get trustee information
     */
    function getTrusteeInfo(address _trustee) public view returns (
        address walletAddress,
        bytes32 shareCommitment,
        bool hasSubmittedCommitment,
        uint256 registeredAt
    ) {
        Trustee memory t = trustees[_trustee];
        return (
            t.walletAddress,
            t.shareCommitment,
            t.hasSubmittedCommitment,
            t.registeredAt
        );
    }
    
    // ===== PHASE 2: Encrypted Voting Functions =====
    
    /**
     * @dev Get encrypted vote for a specific voter in an election
     * @param _electionId The election ID
     * @param _voter The voter address
     */
    function getEncryptedVote(uint256 _electionId, address _voter) 
        public 
        view 
        returns (
            uint256 electionId,
            address voter,
            string memory ipfsCID,
            uint256 timestamp,
            bool exists
        ) 
    {
        EncryptedVote memory ev = encryptedVotes[_electionId][_voter];
        return (
            ev.electionId,
            ev.voter,
            ev.ipfsCID,
            ev.timestamp,
            ev.exists
        );
    }
    
    /**
     * @dev Store encrypted tally for an election (after homomorphic aggregation)
     * @param _electionId The election ID
     * @param _encryptedTally The homomorphically aggregated encrypted total
     */
    function storeEncryptedTally(
        uint256 _electionId,
        string memory _encryptedTally
    ) public {
        require(elections[_electionId].id != 0, "!election");
        require(msg.sender == admin || msg.sender == elections[_electionId].organizer, "!auth");
        require(!elections[_electionId].tallyStored, "!dup");
        require(bytes(_encryptedTally).length > 0, "!tally");
        require(block.timestamp > elections[_electionId].endTime, "!ended");
        
        uint256 voteCount = encryptedVoters[_electionId].length;
        require(voteCount > 0, "!votes");
        
        elections[_electionId].encryptedTally = _encryptedTally;
        elections[_electionId].tallyStored = true;
        elections[_electionId].totalVotes = voteCount;
        
        emit EncryptedTallyStored(_electionId, _encryptedTally, voteCount, block.timestamp);
    }
    
    /**
     * @dev Get encrypted tally for an election
     * @param _electionId The election ID
     */
    function getEncryptedTally(uint256 _electionId)
        public
        view
        returns (
            string memory encryptedTally,
            uint256 totalVotes,
            bool tallyStored
        )
    {
        require(elections[_electionId].id != 0, "!election");
        
        return (
            elections[_electionId].encryptedTally,
            elections[_electionId].totalVotes,
            elections[_electionId].tallyStored
        );
    }
    
    /**
     * @dev Get all voters who cast encrypted votes in an election
     * @param _electionId The election ID
     */
    function getEncryptedVoters(uint256 _electionId) 
        public 
        view 
        returns (address[] memory) 
    {
        return encryptedVoters[_electionId];
    }
    
    /**
     * @dev Get count of encrypted votes in an election
     * @param _electionId The election ID
     */
    function getEncryptedVoteCount(uint256 _electionId) 
        public 
        view 
        returns (uint256) 
    {
        return encryptedVoters[_electionId].length;
    }
    
    event VoterRegistered(
        address indexed wallet,
        string name,
        string email,
        uint256 timestamp
    );
    
    event CandidateRegistered(
        address indexed wallet,
        string name,
        string email,
        uint256 timestamp
    );

    event OrganizerRegistered(
        address indexed applicant,
        string organizationName,
        uint256 timestamp
    );

    event VoterVerified(
        address indexed wallet,
        uint256 timestamp
    );

    event CandidateVerified(
        address indexed wallet,
        uint256 timestamp
    );

    event OrganizerVerified(
        address indexed applicant,
        uint256 timestamp
    );

    event OrganizerRejected(
        address indexed applicant,
        uint256 timestamp
    );

    event ElectionCreated(
        uint256 indexed electionId,
        string title,
        address indexed organizer,
        uint256 nominationStartTime,
        uint256 nominationEndTime,
        uint256 startTime,
        uint256 endTime,
        uint256 timestamp
    );

    event CandidateApplied(
        uint256 indexed electionId,
        address indexed candidateWallet,
        uint256 timestamp
    );

    event CandidateApproved(
        uint256 indexed electionId,
        address indexed candidateWallet,
        address indexed approver,
        uint256 timestamp
    );

    event CandidateRejected(
        uint256 indexed electionId,
        address indexed candidateWallet,
        address indexed rejector,
        uint256 timestamp
    );

    event VoteCast(
        uint256 indexed electionId,
        address indexed voter,
        address indexed candidate,
        uint256 timestamp
    );

    // Common functions
    function isICRegistered(string memory _ic) public view returns (bool) {
        bytes32 icHash = keccak256(abi.encodePacked(_ic));
        return usedICs[icHash];
    }
    
    function isEmailRegistered(string memory _email) public view returns (bool) {
        return usedEmails[_email];
    }
    
    //////////////////
    // Voter Logics //
    //////////////////
    function registerVoter(
        string memory _name,
        string memory _ic,
        string memory _email
    ) public returns (bytes32) {
        require(!voters[msg.sender].isRegistered, "registered");

        bytes32 icHash = keccak256(abi.encodePacked(_ic));
        require(!usedICs[icHash], "IC used");
        require(!usedEmails[_email], "email used");
        
        bytes32 verificationCode = keccak256(
            abi.encodePacked(
                msg.sender,
                _name,
                _ic,
                _email,
                block.timestamp
            )
        );
        voters[msg.sender] = Voter({
            wallet: msg.sender,
            name: _name,
            icHash: icHash,
            email: _email,
            status: "PENDING_VERIFICATION",
            verificationCode: verificationCode,
            registeredAt: block.timestamp,
            verifiedAt: 0,
            isRegistered: true
        });
        voterAddresses.push(msg.sender);
        usedICs[icHash] = true;
        usedEmails[_email] = true;
        
        emit VoterRegistered(msg.sender, _name, _email, block.timestamp);
        
        return verificationCode;
    }
    
    function verifyVoter(bytes32 _verificationCode) public {
        require(voters[msg.sender].isRegistered, "!registered");
        require(
            voters[msg.sender].verificationCode == _verificationCode,
            "!code"
        );
        require(
            keccak256(abi.encodePacked(voters[msg.sender].status)) == 
            keccak256(abi.encodePacked("PENDING_VERIFICATION")),
            "verified"
        );
        
        voters[msg.sender].status = "VERIFIED";
        voters[msg.sender].verifiedAt = block.timestamp;
        
        emit VoterVerified(msg.sender, block.timestamp);
    }
    
    // ZKP-based verification for voters (uses VoteWithICAgeCheck circuit — Verifier.sol)
    // Public signals: [ageThreshold, nullifierHash, electionId, voterCommitment,
    //                  currentYear, currentMonth, currentDay]
    // electionId must be 0 (registration sentinel) to distinguish from actual votes.
    function verifyVoterWithZKP(
        uint[2] calldata _pA,
        uint[2][2] calldata _pB,
        uint[2] calldata _pC,
        uint[7] calldata _pubSignals
    ) public {
        require(voters[msg.sender].isRegistered, "!registered");
        require(
            keccak256(abi.encodePacked(voters[msg.sender].status)) ==
            keccak256(abi.encodePacked("PENDING_VERIFICATION")),
            "!pending"
        );
        require(address(voteVerifier) != address(0), "!verifier");

        // ageThreshold must be 18
        require(_pubSignals[0] == 18, "!age");

        // electionId must be 0 (marks this as a registration proof, not a vote)
        require(_pubSignals[2] == 0, "!electionId");

        // voterCommitment must be non-zero
        require(_pubSignals[3] != 0, "!commitment");

        // Validate proof date matches on-chain block date (prevents proof replay)
        (uint256 blockYear, uint256 blockMonth, uint256 blockDay) = _timestampToDate(block.timestamp);
        require(_pubSignals[4] == blockYear,  "!year");
        require(_pubSignals[5] == blockMonth, "!month");
        require(_pubSignals[6] == blockDay,   "!day");

        // Verify ZK proof
        require(voteVerifier.verifyProof(_pA, _pB, _pC, _pubSignals), "!proof");

        // Store the voter's Poseidon commitment on-chain
        // This enables anonymous voting without linking address to election participation
        bytes32 commitment = bytes32(_pubSignals[3]);
        if (!voterCommitments[commitment]) {
            voterCommitments[commitment] = true;
            emit VoterCommitmentStored(commitment, block.timestamp);
        }

        // Mark voter as VERIFIED
        voters[msg.sender].status = "VERIFIED";
        voters[msg.sender].verifiedAt = block.timestamp;

        emit VoterVerified(msg.sender, block.timestamp);
    }

    function isVoterRegistered(address _wallet) public view returns (bool) {
        return voters[_wallet].isRegistered;
    }

    // Combined function to check if a wallet is registered as voter or candidate
    function isWalletRegistered(address _wallet) public view returns (bool) {
        return voters[_wallet].isRegistered || candidates[_wallet].isRegistered;
    }

    function getAllVoterAddresses() public view returns (address[] memory) {
        return voterAddresses;
    }

    function getTotalRegisteredVoters() public view returns (uint256) {
        return voterAddresses.length;
    }
    
    function getVoterInfo(address _wallet) public view returns (
        string memory name,
        string memory email,
        string memory status,
        uint256 registeredAt,
        uint256 verifiedAt
    ) {
        require(voters[_wallet].isRegistered, "!voter");
        
        Voter memory voter = voters[_wallet];
        return (
            voter.name,
            voter.email,
            voter.status,
            voter.registeredAt,
            voter.verifiedAt
        );
    }

    // function getVotersBatch(uint256 _start, uint256 _count) public view returns (
