    //         address voterAddress = voterAddresses[_start + i];
    //         Voter memory voter = voters[voterAddress];
            
    //         wallets[i] = voter.wallet;
    //         names[i] = voter.name;
    //         emails[i] = voter.email;
    //         statuses[i] = voter.status;
    //         registeredAts[i] = voter.registeredAt;
    //     }
        
